import fs from 'fs';
import path from 'path';

const ledgerPath = 'open-source/gnosis/FORMAL_LEDGER.md';
const content = fs.readFileSync(ledgerPath, 'utf8');
const links = content.match(/\[.*?\]\((.*?)\)/g) || [];

console.log(`Checking ${links.length} links in ${ledgerPath}...`);

for (const link of links) {
    const match = link.match(/\[.*?\]\((.*?)\)/);
    if (match) {
        let target = match[1];
        if (target.startsWith('./')) {
            target = path.join('open-source/gnosis', target);
        } else if (target.startsWith('../')) {
             target = path.join('open-source/gnosis', target);
        }
        
        if (!target.includes('#') && !fs.existsSync(target)) {
            console.log(`Broken link: ${link} -> ${target}`);
        }
    }
}
